// src/Firebase.js

import { initializeApp } from "firebase/app";
import {
  getAuth,
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  onAuthStateChanged,
  signOut
} from "firebase/auth";
import {
  getFirestore,
  collection,
  addDoc,
  getDocs,
  updateDoc,
  doc,
  query,
  orderBy,
  serverTimestamp
} from "firebase/firestore";

// Your Firebase configuration object
const firebaseConfig = {
  apiKey: "AIzaSyDi5B9roo9nQ0VFfb4sWDrZM0WpIYKiqPQ",
  authDomain: "wildlifedu-website.firebaseapp.com",
  projectId: "wildlifedu-website",
  storageBucket: "wildlifedu-website.appspot.com",
  messagingSenderId: "252121860688",
  appId: "1:252121860688:web:c8bec950ce14ce8f7b5f55",
  measurementId: "G-F5F9G7KD78",
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);

// Initialize Firebase services
const auth = getAuth(app);
const db = getFirestore(app);

// Authentication Functions
const signUp = async (email, password) => {
  try {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    return userCredential.user;
  } catch (error) {
    console.error("Error during sign up:", error.message);
    throw error;
  }
};

const login = async (email, password) => {
  try {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    return userCredential.user;
  } catch (error) {
    console.error("Error during login:", error.message);
    throw error;
  }
};

const logout = async () => {
  try {
    await signOut(auth);
  } catch (error) {
    console.error("Error during logout:", error.message);
    throw error;
  }
};

// Firestore Functions
const addPost = async (post) => {
  try {
    const postsRef = collection(db, "posts");
    const docRef = await addDoc(postsRef, {
      ...post,
      createdAt: serverTimestamp(),
      userId: auth.currentUser?.uid
    });
    return docRef.id;
  } catch (error) {
    console.error("Error adding post:", error.message);
    throw error;
  }
};

const getPosts = async () => {
  try {
    const postsRef = collection(db, "posts");
    const q = query(postsRef, orderBy("createdAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));
  } catch (error) {
    console.error("Error getting posts:", error.message);
    throw error;
  }
};

const updatePost = async (id, updatedData) => {
  try {
    const postRef = doc(db, "posts", id);
    await updateDoc(postRef, updatedData);
  } catch (error) {
    console.error("Error updating post:", error.message);
    throw error;
  }
};

// Export all functions
export {
  auth,
  db,
  signUp,
  login,
  logout,
  addPost,
  getPosts,
  updatePost,
  onAuthStateChanged
};
