import React from 'react';
import '../styles/Education.css';

const Education = () => {
  return (
    <div className="education-container">
      <section className="education-hero fade-in">
        <div className="container">
          <h1 className="slide-in-down">Educational Resources</h1>
          <p className="slide-in-up">Learn about wildlife conservation and endangered species in Africa</p>
        </div>
      </section>

      <section className="education-content">
        <div className="container">
          <div className="grid grid-2">
            <div className="card scale-in">
              <h3>Endangered Species</h3>
              <p>Learn about Africa's most endangered species and what we're doing to protect them.</p>
              <ul>
                <li>African Elephant</li>
                <li>Black Rhino</li>
                <li>Mountain Gorilla</li>
                <li>African Wild Dog</li>
              </ul>
            </div>

            <div className="card scale-in" style={{ animationDelay: '0.2s' }}>
              <h3>Conservation Efforts</h3>
              <p>Discover our ongoing conservation projects and how you can get involved.</p>
              <ul>
                <li>Habitat Protection</li>
                <li>Anti-Poaching Initiatives</li>
                <li>Community Education</li>
                <li>Research Programs</li>
              </ul>
            </div>
          </div>

          <div className="education-resources">
            <h2 className="slide-in-up">Learning Materials</h2>
            <div className="grid grid-3">
              <div className="resource-card scale-in">
                <h4>Interactive Maps</h4>
                <p>Explore wildlife habitats and conservation areas across Africa.</p>
              </div>
              <div className="resource-card scale-in" style={{ animationDelay: '0.1s' }}>
                <h4>Video Library</h4>
                <p>Watch documentaries and educational videos about wildlife conservation.</p>
              </div>
              <div className="resource-card scale-in" style={{ animationDelay: '0.2s' }}>
                <h4>Research Papers</h4>
                <p>Access scientific research and conservation studies.</p>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Education; 