import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { collection, getDocs } from 'firebase/firestore';
import { db } from './Firebase';
import '../styles/Courses.css';

const Courses = () => {
  const [courses, setCourses] = useState([]);
  const [activeFilter, setActiveFilter] = useState('all');
  const [user] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const coursesCollection = collection(db, 'courses');
        const snapshot = await getDocs(coursesCollection);
        const coursesData = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setCourses(coursesData);
      } catch (error) {
        console.error('Error fetching courses:', error);
      }
    };

    fetchCourses();
  }, []);

  const handleEnroll = (courseId) => {
    if (!user) {
      navigate('/login');
      return;
    }
    // Handle course enrollment logic here
    console.log('Enrolling in course:', courseId);
  };

  const filteredCourses = courses.filter(course => {
    if (activeFilter === 'all') return true;
    return course.difficulty === activeFilter;
  });

  return (
    <div className="courses-page">
      <div className="courses-hero">
        <h1>Wildlife Conservation Courses</h1>
        <p>Learn about wildlife conservation, ecology, and sustainable practices</p>
      </div>

      <div className="courses-container">
        <div className="course-filters">
          <button 
            className={`filter-toggle ${activeFilter === 'all' ? 'active' : ''}`}
            onClick={() => setActiveFilter('all')}
          >
            All Courses
          </button>
          <button 
            className={`filter-toggle ${activeFilter === 'beginner' ? 'active' : ''}`}
            onClick={() => setActiveFilter('beginner')}
          >
            Beginner
          </button>
          <button 
            className={`filter-toggle ${activeFilter === 'intermediate' ? 'active' : ''}`}
            onClick={() => setActiveFilter('intermediate')}
          >
            Intermediate
          </button>
          <button 
            className={`filter-toggle ${activeFilter === 'advanced' ? 'active' : ''}`}
            onClick={() => setActiveFilter('advanced')}
          >
            Advanced
          </button>
        </div>

        <div className="courses-grid">
          {filteredCourses.map(course => (
            <div key={course.id} className="course-card">
              <div className="course-image">
                <img src={course.image} alt={course.title} />
                <span className={`difficulty-badge ${course.difficulty}`}>
                  {course.difficulty}
                </span>
              </div>
              <div className="course-content">
                <h3>{course.title}</h3>
                <p className="course-description">{course.description}</p>
                <div className="course-meta">
                  <span>
                    <i className="fas fa-clock"></i> {course.duration}
                  </span>
                  <span>
                    <i className="fas fa-user"></i> {course.instructor}
                  </span>
                  <span>
                    <i className="fas fa-star"></i> {course.rating}
                  </span>
                </div>
                <div className="course-actions">
                  <button 
                    className="enroll-btn"
                    onClick={() => handleEnroll(course.id)}
                  >
                    Enroll Now
                  </button>
                  <span className="enrolled-count">
                    {course.enrolled} students enrolled
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="discussion-section">
          <h2>Course Discussions</h2>
          {user ? (
            <div className="discussion-content">
              <div className="discussion-form">
                <textarea placeholder="Share your thoughts or ask a question..."></textarea>
                <button className="post-btn">Post Discussion</button>
              </div>
              <div className="discussions-list">
                {/* Discussion items will be rendered here */}
              </div>
            </div>
          ) : (
            <div className="login-prompt">
              <p>Please <a href="/login">log in</a> to participate in course discussions.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Courses;
