import React from 'react';
import '../styles/Events.css';

const Events = () => {
  return (
    <div className="events-container">
      <section className="events-hero fade-in">
        <div className="container">
          <h1 className="slide-in-down">Upcoming Events</h1>
          <p className="slide-in-up">Join us in our conservation efforts and community activities</p>
        </div>
      </section>

      <section className="upcoming-events">
        <div className="container">
          <h2 className="slide-in-up">Featured Events</h2>
          <div className="grid grid-2">
            <div className="event-card scale-in">
              <div className="event-date">
                <span className="day">25</span>
                <span className="month">Apr</span>
              </div>
              <div className="event-content">
                <h3>Wildlife Conservation Workshop</h3>
                <p>Join our experts for a hands-on workshop about wildlife conservation techniques.</p>
                <div className="event-details">
                  <p><strong>Location:</strong> Nairobi, Kenya</p>
                  <p><strong>Time:</strong> 9:00 AM - 4:00 PM</p>
                </div>
                <button className="btn btn-primary">Register Now</button>
              </div>
            </div>

            <div className="event-card scale-in" style={{ animationDelay: '0.2s' }}>
              <div className="event-date">
                <span className="day">15</span>
                <span className="month">May</span>
              </div>
              <div className="event-content">
                <h3>Community Cleanup Day</h3>
                <p>Help clean up local habitats and learn about environmental conservation.</p>
                <div className="event-details">
                  <p><strong>Location:</strong> Victoria Falls, Zimbabwe</p>
                  <p><strong>Time:</strong> 8:00 AM - 2:00 PM</p>
                </div>
                <button className="btn btn-primary">Register Now</button>
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="past-events">
        <div className="container">
          <h2 className="slide-in-up">Past Events</h2>
          <div className="grid grid-3">
            <div className="past-event-card scale-in">
              <h3>Wildlife Photography Exhibition</h3>
              <p>March 2024</p>
              <p>Showcasing stunning wildlife photography from across Africa.</p>
            </div>
            <div className="past-event-card scale-in" style={{ animationDelay: '0.1s' }}>
              <h3>Conservation Conference</h3>
              <p>February 2024</p>
              <p>International conference on wildlife conservation strategies.</p>
            </div>
            <div className="past-event-card scale-in" style={{ animationDelay: '0.2s' }}>
              <h3>Youth Education Program</h3>
              <p>January 2024</p>
              <p>Educational program for young conservationists.</p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Events; 