import React, { useState, useEffect } from 'react';
import { auth, db } from './Firebase';
import { collection, getDocs, deleteDoc, doc, addDoc, updateDoc } from 'firebase/firestore';
import { useNavigate } from 'react-router-dom';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [users, setUsers] = useState([]);
  const [courses, setCourses] = useState([]);
  const [events, setEvents] = useState([]);
  const [forumPosts, setForumPosts] = useState([]);
  const [donations, setDonations] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    // Check if user is authenticated and is an admin
    const unsubscribe = auth.onAuthStateChanged((user) => {
      if (!user || !user.email.endsWith('@careafrica.org')) {
        navigate('/login');
      } else {
        fetchData();
      }
    });

    return () => unsubscribe();
  }, [navigate]);

  const fetchData = async () => {
    try {
      // Fetch users
      const usersSnapshot = await getDocs(collection(db, 'users'));
      setUsers(usersSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));

      // Fetch courses
      const coursesSnapshot = await getDocs(collection(db, 'courses'));
      setCourses(coursesSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));

      // Fetch events
      const eventsSnapshot = await getDocs(collection(db, 'events'));
      setEvents(eventsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));

      // Fetch forum posts
      const forumSnapshot = await getDocs(collection(db, 'forum'));
      setForumPosts(forumSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));

      // Fetch donations
      const donationsSnapshot = await getDocs(collection(db, 'donations'));
      setDonations(donationsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const handleDelete = async (collectionName, id) => {
    if (window.confirm('Are you sure you want to delete this item?')) {
      try {
        await deleteDoc(doc(db, collectionName, id));
        fetchData(); // Refresh data after deletion
      } catch (error) {
        console.error('Error deleting item:', error);
      }
    }
  };

  const handleAddCourse = async (courseData) => {
    try {
      await addDoc(collection(db, 'courses'), courseData);
      fetchData();
    } catch (error) {
      console.error('Error adding course:', error);
    }
  };

  const handleUpdateUser = async (userId, userData) => {
    try {
      await updateDoc(doc(db, 'users', userId), userData);
      fetchData();
    } catch (error) {
      console.error('Error updating user:', error);
    }
  };

  const renderOverview = () => (
    <div className="dashboard-overview">
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Total Users</h3>
          <p>{users.length}</p>
        </div>
        <div className="stat-card">
          <h3>Active Courses</h3>
          <p>{courses.length}</p>
        </div>
        <div className="stat-card">
          <h3>Upcoming Events</h3>
          <p>{events.length}</p>
        </div>
        <div className="stat-card">
          <h3>Total Donations</h3>
          <p>${donations.reduce((sum, d) => sum + d.amount, 0)}</p>
        </div>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="dashboard-section">
      <h2>User Management</h2>
      <table className="data-table">
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Role</th>
            <th>Joined</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            <tr key={user.id}>
              <td>{user.name}</td>
              <td>{user.email}</td>
              <td>{user.role || 'User'}</td>
              <td>{new Date(user.createdAt).toLocaleDateString()}</td>
              <td>
                <button className="action-button edit">Edit</button>
                <button className="action-button delete" onClick={() => handleDelete('users', user.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderCourses = () => (
    <div className="dashboard-section">
      <h2>Course Management</h2>
      <button className="add-button">Add New Course</button>
      <table className="data-table">
        <thead>
          <tr>
            <th>Title</th>
            <th>Instructor</th>
            <th>Difficulty</th>
            <th>Enrolled</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {courses.map(course => (
            <tr key={course.id}>
              <td>{course.title}</td>
              <td>{course.instructor}</td>
              <td>{course.difficulty}</td>
              <td>{course.enrolled}</td>
              <td>{course.status}</td>
              <td>
                <button className="action-button edit">Edit</button>
                <button className="action-button delete" onClick={() => handleDelete('courses', course.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderEvents = () => (
    <div className="dashboard-section">
      <h2>Event Management</h2>
      <button className="add-button">Add New Event</button>
      <table className="data-table">
        <thead>
          <tr>
            <th>Title</th>
            <th>Date</th>
            <th>Location</th>
            <th>Attendees</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {events.map(event => (
            <tr key={event.id}>
              <td>{event.title}</td>
              <td>{new Date(event.date).toLocaleDateString()}</td>
              <td>{event.location}</td>
              <td>{event.attendees}</td>
              <td>{event.status}</td>
              <td>
                <button className="action-button edit">Edit</button>
                <button className="action-button delete" onClick={() => handleDelete('events', event.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderForum = () => (
    <div className="dashboard-section">
      <h2>Forum Management</h2>
      <table className="data-table">
        <thead>
          <tr>
            <th>Title</th>
            <th>Author</th>
            <th>Date</th>
            <th>Replies</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {forumPosts.map(post => (
            <tr key={post.id}>
              <td>{post.title}</td>
              <td>{post.author}</td>
              <td>{new Date(post.createdAt).toLocaleDateString()}</td>
              <td>{post.replies}</td>
              <td>{post.status}</td>
              <td>
                <button className="action-button edit">Edit</button>
                <button className="action-button delete" onClick={() => handleDelete('forum', post.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderDonations = () => (
    <div className="dashboard-section">
      <h2>Donation Management</h2>
      <table className="data-table">
        <thead>
          <tr>
            <th>Donor</th>
            <th>Amount</th>
            <th>Date</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {donations.map(donation => (
            <tr key={donation.id}>
              <td>{donation.donor}</td>
              <td>${donation.amount}</td>
              <td>{new Date(donation.date).toLocaleDateString()}</td>
              <td>{donation.status}</td>
              <td>
                <button className="action-button view">View</button>
                <button className="action-button update">Update Status</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  return (
    <div className="admin-dashboard">
      <div className="sidebar">
        <h2>Admin Dashboard</h2>
        <nav>
          <button 
            className={activeTab === 'overview' ? 'active' : ''}
            onClick={() => setActiveTab('overview')}
          >
            Overview
          </button>
          <button 
            className={activeTab === 'users' ? 'active' : ''}
            onClick={() => setActiveTab('users')}
          >
            Users
          </button>
          <button 
            className={activeTab === 'courses' ? 'active' : ''}
            onClick={() => setActiveTab('courses')}
          >
            Courses
          </button>
          <button 
            className={activeTab === 'events' ? 'active' : ''}
            onClick={() => setActiveTab('events')}
          >
            Events
          </button>
          <button 
            className={activeTab === 'forum' ? 'active' : ''}
            onClick={() => setActiveTab('forum')}
          >
            Forum
          </button>
          <button 
            className={activeTab === 'donations' ? 'active' : ''}
            onClick={() => setActiveTab('donations')}
          >
            Donations
          </button>
        </nav>
      </div>
      <div className="main-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'users' && renderUsers()}
        {activeTab === 'courses' && renderCourses()}
        {activeTab === 'events' && renderEvents()}
        {activeTab === 'forum' && renderForum()}
        {activeTab === 'donations' && renderDonations()}
      </div>
    </div>
  );
};

export default AdminDashboard; 